import { useState } from "react";
import { loginUser, registerUser } from "../firebase/config";

const AuthPage = ({ onLogin }) => {  // ✅ Remove students from here
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [name, setName] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError("");

    if (isLogin) {
      // ✅ LOGIN - Firebase se authenticate karo
      const result = await loginUser(email, password);
      
      if (result.success) {
        // Check for admin (hardcoded)
        if (email === "admin@hostelhub.com" && password === "admin123") {
          onLogin({ 
            id: "admin", 
            name: "Admin", 
            email, 
            role: "admin" 
          });
        } else {
          onLogin({ 
            id: result.user.uid, 
            name: email.split('@')[0], 
            email, 
            role: "student" 
          });
        }
      } else {
        setError("Invalid email or password");
      }
    } else {
      // ✅ REGISTER - Firebase me naya user banao
      if (!name) {
        setError("Please enter your name");
        setLoading(false);
        return;
      }
      
      const result = await registerUser(email, password, name);
      
      if (result.success) {
        onLogin({ 
          id: result.user.uid, 
          name: name, 
          email, 
          role: "student" 
        });
      } else {
        setError(result.error);
      }
    }
    
    setLoading(false);
  };

  return (
    <div style={{
      minHeight: "100vh",
      background: "linear-gradient(135deg, #667eea 0%, #764ba2 100%)",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      padding: "20px"
    }}>
      <div style={{
        background: "white",
        padding: "40px",
        borderRadius: "16px",
        width: "450px",
        maxWidth: "100%",
        boxShadow: "0 20px 60px rgba(0,0,0,0.3)"
      }}>
        <div style={{ textAlign: "center", marginBottom: "32px" }}>
          <div style={{ fontSize: "48px", marginBottom: "8px" }}>🏨</div>
          <h1 style={{ fontSize: "28px", fontWeight: "bold" }}>HostelHub</h1>
          <p style={{ color: "#64748b" }}>
            {isLogin ? "Sign in to your account" : "Create a new account"}
          </p>
        </div>

        {error && (
          <div style={{
            background: "#fee2e2",
            color: "#991b1b",
            padding: "12px",
            borderRadius: "8px",
            marginBottom: "20px",
            fontSize: "14px"
          }}>
            ⚠️ {error}
          </div>
        )}

        <form onSubmit={handleSubmit}>
          {!isLogin && (
            <div style={{ marginBottom: "16px" }}>
              <label style={{ display: "block", marginBottom: "6px", fontWeight: "500" }}>
                Full Name
              </label>
              <input
                type="text"
                value={name}
                onChange={(e) => setName(e.target.value)}
                placeholder="Enter your name"
                required
                style={{
                  width: "100%",
                  padding: "12px",
                  border: "1px solid #cbd5e1",
                  borderRadius: "8px",
                  fontSize: "14px"
                }}
              />
            </div>
          )}

          <div style={{ marginBottom: "16px" }}>
            <label style={{ display: "block", marginBottom: "6px", fontWeight: "500" }}>
              Email Address
            </label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="Enter your email"
              required
              style={{
                width: "100%",
                padding: "12px",
                border: "1px solid #cbd5e1",
                borderRadius: "8px",
                fontSize: "14px"
              }}
            />
          </div>

          <div style={{ marginBottom: "24px" }}>
            <label style={{ display: "block", marginBottom: "6px", fontWeight: "500" }}>
              Password
            </label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Enter your password"
              required
              style={{
                width: "100%",
                padding: "12px",
                border: "1px solid #cbd5e1",
                borderRadius: "8px",
                fontSize: "14px"
              }}
            />
          </div>

          <button
            type="submit"
            disabled={loading}
            style={{
              width: "100%",
              padding: "12px",
              background: "#3b82f6",
              color: "white",
              border: "none",
              borderRadius: "8px",
              fontSize: "16px",
              fontWeight: "500",
              cursor: "pointer",
              opacity: loading ? 0.7 : 1
            }}
          >
            {loading ? "Please wait..." : (isLogin ? "Sign In" : "Register")}
          </button>
        </form>

        <div style={{ textAlign: "center", marginTop: "24px" }}>
          <button
            onClick={() => setIsLogin(!isLogin)}
            style={{
              background: "none",
              border: "none",
              color: "#3b82f6",
              cursor: "pointer",
              fontSize: "14px"
            }}
          >
            {isLogin ? "Don't have an account? Register" : "Already have an account? Sign In"}
          </button>
        </div>

        {/* Demo Credentials */}
        <div style={{
          marginTop: "24px",
          padding: "12px",
          background: "#f8fafc",
          borderRadius: "8px",
          fontSize: "12px",
          textAlign: "center"
        }}>
          <p style={{ fontWeight: "bold", marginBottom: "4px" }}>Demo Credentials:</p>
          <p>Admin: admin@hostelhub.com / admin123</p>
          <p>Or Register as new student</p>
        </div>
      </div>
    </div>
  );
};

export default AuthPage;
